import type { Metadata } from "next";
import Loading from "./Loading";

export const metadata: Metadata = {
  title: "配車 / 積込 / 配送ルート | ぐんじょう WMS",
  description:
    "配車・積込・配送ルート（出荷確定後の出庫工程）の画面。便（ルート）と車両（種別・最大積載量kg・最大容積m³）・ドライバー・出発予定時刻・ステータス（積込前 / 積込中 / 出発済）を表示。出荷をこの車両へ割り当てると重量積載率・容積積載率の2つの容量メーターがしきい値で色付き（空き / 満載間近 / 超過）に更新され、割当ボタンにフォーカスすると積んだ後をプレビュー。積載超過（積み残し）はブロックして次便振替（理由付き）。2段スキャン（① 車両/便コード ② 割当済カートン）で積込確定、対象外カートンはエラー読み上げ。配送ルートはお届け先を順序付け（積込はLIFO=配達の逆順）して到着予定（ETA）を再計算。出発確定ゲート（割当済が全て積込済・積載超過なし・ルート設定済までブロック）、配車サマリ（積載率・停車数・所要/帰着）、配送指示書印刷を備えたドック端末向けツールです。",
};

export default function LoadingPage() {
  return <Loading />;
}

"use client";

import * as React from "react";
import { cn } from "@gunjo/ui";

/**
 * 積載率メーター — hand-rolled capacity meter.
 *
 * Why not `@gunjo/ui` <Progress tone>: Progress is a single fill that takes a
 * *literal* tone. A truck load meter needs (1) a threshold-DERIVED tone
 * (空き→ok / 満載間近→warning / 超過→over) and (2) a current + INCOMING overlay
 * so the dispatcher can preview "after I add this shipment". Progress does
 * neither, so this composes raw tokens to provide both. See FINDINGS-51.
 */

export type CapacityTone = "ok" | "warning" | "over";

export interface CapacityMeterProps {
  /** Accessible name, e.g. "重量積載率". */
  label: string;
  /** Currently loaded/assigned amount. */
  value: number;
  /** Vehicle capacity (max). */
  max: number;
  /** Optional incoming delta previewed as a ghost segment (e.g. the shipment about to be added). */
  incoming?: number;
  /** Unit suffix for the readout, e.g. "kg" or "m³". */
  unit: string;
  /** Threshold ratios. Default { warning: 0.8, over: 1.0 }. */
  thresholds?: { warning: number; over: number };
  /** Compact inline row (label + bar + % on one line). */
  size?: "default" | "inline";
  /** Format the numeric readout. Default toLocaleString-ish. */
  format?: (n: number) => string;
  className?: string;
}

export function toneForRatio(
  ratio: number,
  thresholds = { warning: 0.8, over: 1.0 },
): CapacityTone {
  if (ratio >= thresholds.over) return "over";
  if (ratio >= thresholds.warning) return "warning";
  return "ok";
}

const TRACK = "bg-secondary";
const FILL: Record<CapacityTone, string> = {
  ok: "bg-success",
  warning: "bg-warning",
  over: "bg-destructive",
};
const TONE_TEXT: Record<CapacityTone, string> = {
  ok: "text-success-strong",
  warning: "text-warning-strong",
  over: "text-destructive",
};
const TONE_LABEL: Record<CapacityTone, string> = {
  ok: "空きあり",
  warning: "満載間近",
  over: "超過",
};

const defaultFormat = (n: number) =>
  new Intl.NumberFormat("ja-JP", { maximumFractionDigits: 1 }).format(n);

export function CapacityMeter({
  label,
  value,
  max,
  incoming = 0,
  unit,
  thresholds = { warning: 0.8, over: 1.0 },
  size = "default",
  format = defaultFormat,
  className,
}: CapacityMeterProps) {
  const safeMax = max > 0 ? max : 1;
  const ratio = value / safeMax;
  const previewRatio = (value + incoming) / safeMax;
  const tone = toneForRatio(ratio, thresholds);
  const previewTone = toneForRatio(previewRatio, thresholds);

  const pct = Math.round(ratio * 100);
  const previewPct = Math.round(previewRatio * 100);

  // Bar widths clamp to 100; the over-band is rendered as a hatch on the right edge.
  const baseW = Math.min(100, Math.max(0, ratio * 100));
  // Incoming ghost starts at baseW and extends; clamp the visible end to 100.
  const ghostStart = baseW;
  const ghostEnd = Math.min(100, Math.max(0, previewRatio * 100));
  const ghostW = Math.max(0, ghostEnd - ghostStart);

  const overflow = previewRatio > 1;

  const readout =
    incoming > 0
      ? `${format(value)} + ${format(incoming)} → ${format(value + incoming)} / ${format(max)} ${unit}`
      : `${format(value)} / ${format(max)} ${unit}`;

  const announced = `${label} ${incoming > 0 ? previewPct : pct}パーセント、${
    TONE_LABEL[incoming > 0 ? previewTone : tone]
  }。${readout}`;

  const Bar = (
    <div
      role="meter"
      aria-label={label}
      aria-valuemin={0}
      aria-valuemax={100}
      aria-valuenow={incoming > 0 ? previewPct : pct}
      aria-valuetext={announced}
      className={cn(
        "relative h-3 w-full overflow-hidden rounded-full",
        TRACK,
        size === "default" && "h-4",
      )}
    >
      {/* base loaded fill */}
      <div
        className={cn("absolute inset-y-0 left-0 rounded-full transition-all", FILL[tone])}
        style={{ width: `${baseW}%` }}
      />
      {/* incoming ghost segment (striped) */}
      {ghostW > 0.5 ? (
        <div
          className={cn(
            "absolute inset-y-0 opacity-70 transition-all",
            FILL[previewTone],
          )}
          style={{
            left: `${ghostStart}%`,
            width: `${ghostW}%`,
            backgroundImage:
              "repeating-linear-gradient(45deg, hsl(var(--background) / 0.45) 0 4px, transparent 4px 8px)",
          }}
        />
      ) : null}
      {/* warning threshold marker */}
      <span
        aria-hidden
        className="absolute inset-y-0 w-px bg-foreground/40"
        style={{ left: `${thresholds.warning * 100}%` }}
      />
      {/* over band flag at 100% */}
      {overflow ? (
        <span
          aria-hidden
          className="absolute inset-y-0 right-0 w-1.5 bg-destructive-strong"
        />
      ) : null}
    </div>
  );

  if (size === "inline") {
    return (
      <div className={cn("flex items-center gap-2", className)}>
        <span className="w-24 shrink-0 text-xs text-muted-foreground">{label}</span>
        <div className="min-w-0 flex-1">{Bar}</div>
        <span
          className={cn(
            "w-12 shrink-0 text-right text-xs font-semibold tabular-nums",
            TONE_TEXT[incoming > 0 ? previewTone : tone],
          )}
        >
          {incoming > 0 ? previewPct : pct}%
        </span>
      </div>
    );
  }

  return (
    <div className={cn("flex flex-col gap-1.5", className)}>
      <div className="flex items-baseline justify-between gap-2">
        <span className="text-sm font-medium text-foreground">{label}</span>
        <span
          className={cn(
            "text-sm font-bold tabular-nums",
            TONE_TEXT[incoming > 0 ? previewTone : tone],
          )}
        >
          {incoming > 0 ? `${pct}% → ${previewPct}%` : `${pct}%`}
          <span className="ml-1.5 text-xs font-medium">
            {TONE_LABEL[incoming > 0 ? previewTone : tone]}
          </span>
        </span>
      </div>
      {Bar}
      <p className="text-xs text-muted-foreground tabular-nums">{readout}</p>
    </div>
  );
}

// 配車 / 積込 / 配送ルート — domain data for the dispatch + truck-loading + route screen.
// All amounts JPY, weights kg, volumes m³. 才 (sai) ≈ 0.0278 m³ shown for reference.

export type LoadState = "未割当" | "積込済";
export type RunStatus = "積込前" | "積込中" | "出発済";

export interface Vehicle {
  id: string;
  name: string; // 車両名 / ナンバー
  type: string; // 種別
  maxWeightKg: number; // 最大積載量
  maxVolumeM3: number; // 最大容積
}

export interface Driver {
  id: string;
  name: string;
}

export interface Stop {
  /** Delivery destination id (one お届け先 can group several shipments). */
  id: string;
  name: string; // お届け先
  address: string;
  /** Minutes of travel from the previous stop (depot for the first). */
  legMinutes: number;
  /** Service (unload) minutes at this stop. */
  serviceMinutes: number;
}

export interface Shipment {
  id: string;
  orderNo: string; // 出荷番号
  /** Carton barcode scanned at load. */
  barcode: string;
  stopId: string; // お届け先 (FK → Stop)
  cartons: number; // 個数
  weightKg: number; // 重量
  volumeM3: number; // 容積
  /** 才 for display (volumetric). */
  sai: number;
  /** Cash-on-delivery / 代引 amount (¥), 0 if none. */
  codAmount: number;
}

export interface Run {
  id: string;
  name: string; // 便 / ルート名
  date: string; // 配送日
  departAt: string; // 出発予定時刻
  vehicleId: string;
  driverId: string;
}

export const VEHICLES: Vehicle[] = [
  { id: "v-2t", name: "品川 100 か 12-34", type: "2tショート", maxWeightKg: 2000, maxVolumeM3: 8.5 },
  { id: "v-3t", name: "品川 100 か 56-78", type: "3tワイド", maxWeightKg: 3000, maxVolumeM3: 12.0 },
  { id: "v-4t", name: "足立 100 か 90-12", type: "4t標準", maxWeightKg: 4000, maxVolumeM3: 16.5 },
