export const DRIVERS: Driver[] = [
  { id: "d-sato", name: "佐藤 健一" },
  { id: "d-tanaka", name: "田中 美咲" },
  { id: "d-yamada", name: "山田 拓也" },
];

export const STOPS: Stop[] = [
  { id: "s-shinagawa", name: "品川物流センター", address: "東京都品川区東品川 2-1", legMinutes: 25, serviceMinutes: 10 },
  { id: "s-ota", name: "大田市場 仲卸 田村屋", address: "東京都大田区東海 3-2-1", legMinutes: 18, serviceMinutes: 15 },
  { id: "s-meguro", name: "目黒ストア 本店", address: "東京都目黒区下目黒 1-8", legMinutes: 22, serviceMinutes: 8 },
  { id: "s-setagaya", name: "世田谷フレッシュ 桜新町店", address: "東京都世田谷区桜新町 2-9", legMinutes: 20, serviceMinutes: 12 },
  { id: "s-chofu", name: "調布デポ", address: "東京都調布市布田 4-3", legMinutes: 28, serviceMinutes: 10 },
];

export const RUN: Run = {
  id: "run-w1-am",
  name: "西部第1便 (午前)",
  date: "2026-06-23",
  departAt: "08:30",
  vehicleId: "v-3t",
  driverId: "d-sato",
};

// Shipments staged for this run. Deliberately sums close-but-over the 3t / 12m³
// vehicle so the over-capacity (積み残し) path is reachable when all are assigned.
export const SHIPMENTS: Shipment[] = [
  { id: "sh-1", orderNo: "OUT-240623-001", barcode: "CTN-7781", stopId: "s-shinagawa", cartons: 6, weightKg: 420, volumeM3: 1.8, sai: 65, codAmount: 0 },
  { id: "sh-2", orderNo: "OUT-240623-002", barcode: "CTN-7782", stopId: "s-ota", cartons: 4, weightKg: 610, volumeM3: 1.4, sai: 50, codAmount: 38000 },
  { id: "sh-3", orderNo: "OUT-240623-003", barcode: "CTN-7783", stopId: "s-meguro", cartons: 8, weightKg: 540, volumeM3: 2.6, sai: 94, codAmount: 0 },
  { id: "sh-4", orderNo: "OUT-240623-004", barcode: "CTN-7784", stopId: "s-setagaya", cartons: 5, weightKg: 480, volumeM3: 2.2, sai: 79, codAmount: 12500 },
  { id: "sh-5", orderNo: "OUT-240623-005", barcode: "CTN-7785", stopId: "s-chofu", cartons: 7, weightKg: 690, volumeM3: 3.1, sai: 112, codAmount: 0 },
  { id: "sh-6", orderNo: "OUT-240623-006", barcode: "CTN-7786", stopId: "s-ota", cartons: 3, weightKg: 350, volumeM3: 1.5, sai: 54, codAmount: 21000 },
];

export const DEPOT_DEPART = "08:30"; // 出発（拠点）

/** Threshold ratios shared by both capacity meters. <warn → ok, [warn,over) → warning, ≥over → destructive. */
export const LOAD_THRESHOLDS = { warning: 0.8, over: 1.0 } as const;

/** Deferral reasons for 積み残し処理. */
export const DEFER_REASONS = [
  "積載容量オーバー (重量)",
  "積載容量オーバー (容積)",
  "次便へ振替 (時間調整)",
  "お届け先休業 / 受取不可",
  "破損 / 要再梱包",
] as const;

"use client";

import * as React from "react";
import {
  IconTruck,
  IconScan,
  IconRoute,
  IconPackage,
  IconArrowUp,
  IconArrowDown,
  IconCircleCheck,
  IconAlertTriangle,
  IconClock,
  IconPrinter,
  IconChevronRight,
} from "@tabler/icons-react";
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  CardDescription,
  Button,
  Badge,
  Alert,
  AlertTitle,
  AlertDescription,
  Select,
  Separator,
  Statistic,
  Delta,
  ScanGate,
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
  formatCurrency,
  formatNumber,
  type ScanGateStage,
  type ScanGateResult,
} from "@gunjo/ui";

import {
  VEHICLES,
  DRIVERS,
  STOPS,
  RUN,
  SHIPMENTS,
  DEFER_REASONS,
  LOAD_THRESHOLDS,
  type Shipment,
  type RunStatus,
} from "./data";
import { CapacityMeter } from "./CapacityMeter";

// ─── helpers ──────────────────────────────────────────────────────────────────
const stopById = (id: string) => STOPS.find((s) => s.id === id);
const fmt1 = (n: number) =>
  new Intl.NumberFormat("ja-JP", { maximumFractionDigits: 1 }).format(n);

function addMinutes(hhmm: string, mins: number): string {
  const [h, m] = hhmm.split(":").map(Number);
  const total = h * 60 + m + mins;
  const hh = Math.floor((total % (24 * 60)) / 60);
  const mm = total % 60;
  return `${String(hh).padStart(2, "0")}:${String(mm).padStart(2, "0")}`;
}

type AssignState = "未割当" | "割当済" | "積込済" | "積み残し";

interface Deferred {
  id: string;
  reason: string;
}

export default function Loading() {
  // run / vehicle / driver pickers
  const [vehicleId, setVehicleId] = React.useState(RUN.vehicleId);
  const [driverId, setDriverId] = React.useState(RUN.driverId);
  const vehicle = VEHICLES.find((v) => v.id === vehicleId) ?? VEHICLES[0];
  const driver = DRIVERS.find((d) => d.id === driverId) ?? DRIVERS[0];

  // assignment + load state, keyed by shipment id
  const [assignment, setAssignment] = React.useState<Record<string, AssignState>>(
    () => Object.fromEntries(SHIPMENTS.map((s) => [s.id, "未割当" as AssignState])),
  );
  const [deferred, setDeferred] = React.useState<Record<string, Deferred>>({});

  // preview: which shipment's "add" is being hovered/focused (incoming overlay)
  const [previewId, setPreviewId] = React.useState<string | null>(null);

  // delivery stop order (ids); first = first delivery. Load order = reverse (LIFO).
  const initialStopOrder = React.useMemo(
    () => Array.from(new Set(SHIPMENTS.map((s) => s.stopId))),
    [],
  );
  const [stopOrder, setStopOrder] = React.useState<string[]>(initialStopOrder);

  // dispatch status
  const [status, setStatus] = React.useState<RunStatus>("積込前");

  // announcements
  const [announce, setAnnounce] = React.useState("");
  const [scanAnnounce, setScanAnnounce] = React.useState<{ ok: boolean; msg: string } | null>(null);
  const [validationMsg, setValidationMsg] = React.useState<string | null>(null);

  // dialogs
  const [deferTarget, setDeferTarget] = React.useState<Shipment | null>(null);
  const [deferReason, setDeferReason] = React.useState<string>(DEFER_REASONS[0]);
  const [summaryOpen, setSummaryOpen] = React.useState(false);
  const [printOpen, setPrintOpen] = React.useState(false);

  const readOnly = status === "出発済";

  // ─── derived load figures ─────────────────────────────────────────────────
  const assignedShipments = SHIPMENTS.filter(
    (s) => assignment[s.id] === "割当済" || assignment[s.id] === "積込済",
  );
  const loadedShipments = SHIPMENTS.filter((s) => assignment[s.id] === "積込済");

  const sum = (arr: Shipment[], key: "weightKg" | "volumeM3" | "cartons" | "codAmount") =>
    arr.reduce((acc, s) => acc + s[key], 0);

  const loadedWeight = sum(assignedShipments, "weightKg");
  const loadedVolume = sum(assignedShipments, "volumeM3");
  const loadedCartons = sum(assignedShipments, "cartons");
  const codTotal = sum(assignedShipments, "codAmount");

  const previewShipment = previewId
    ? SHIPMENTS.find((s) => s.id === previewId && assignment[s.id] === "未割当")
    : null;
  const incomingWeight = previewShipment ? previewShipment.weightKg : 0;
  const incomingVolume = previewShipment ? previewShipment.volumeM3 : 0;

  const remWeight = vehicle.maxWeightKg - loadedWeight;
  const remVolume = vehicle.maxVolumeM3 - loadedVolume;

  const overWeight = loadedWeight > vehicle.maxWeightKg;
  const overVolume = loadedVolume > vehicle.maxVolumeM3;
  const overCapacity = overWeight || overVolume;

  // ─── route / ETA ──────────────────────────────────────────────────────────
  const orderedStops = stopOrder
    .map((id) => stopById(id))
    .filter((s): s is NonNullable<typeof s> => Boolean(s));

  const stopEtas = React.useMemo(() => {
    let clock = RUN.departAt;
    return orderedStops.map((s) => {
      const arrive = addMinutes(clock, s.legMinutes);
      clock = addMinutes(arrive, s.serviceMinutes);
      const cartons = sum(
        assignedShipments.filter((sh) => sh.stopId === s.id),
        "cartons",
      );
      return { stop: s, eta: arrive, depart: clock, cartons };
    });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [orderedStops, assignedShipments]);

  const totalMinutes = orderedStops.reduce(
    (acc, s) => acc + s.legMinutes + s.serviceMinutes,
    0,
  );
  const finishEta = stopEtas.length ? stopEtas[stopEtas.length - 1].depart : RUN.departAt;
  const stopsWithLoad = orderedStops.filter((s) =>
    assignedShipments.some((sh) => sh.stopId === s.id),
  ).length;

  // ─── dispatch gate ─────────────────────────────────────────────────────────
  const allAssignedAreLoaded =
    assignedShipments.length > 0 &&
    assignedShipments.every((s) => assignment[s.id] === "積込済");
  const stopsSequenced = stopsWithLoad > 0;
  const canDispatch =
    !overCapacity && allAssignedAreLoaded && stopsSequenced && status === "積込中";

  const dispatchBlockers: string[] = [];
  if (overCapacity) dispatchBlockers.push("積載量が超過しています（積み残し処理が必要）");
  if (assignedShipments.length === 0) dispatchBlockers.push("出荷が1件も割り当てられていません");
  if (assignedShipments.length > 0 && !allAssignedAreLoaded)
    dispatchBlockers.push("割当済で未スキャン（未積込）の出荷があります");
  if (!stopsSequenced) dispatchBlockers.push("配送ルート（お届け先）が未設定です");

  // ─── actions ───────────────────────────────────────────────────────────────
  function bumpStatusToLoading() {
    setStatus((prev) => (prev === "積込前" ? "積込中" : prev));
  }

  function assign(s: Shipment) {
    if (readOnly) return;
    // block over-capacity on assign — flag as 積み残し candidate but warn loudly
    const nextWeight = loadedWeight + s.weightKg;
    const nextVolume = loadedVolume + s.volumeM3;
    if (nextWeight > vehicle.maxWeightKg || nextVolume > vehicle.maxVolumeM3) {
      const which =
        nextWeight > vehicle.maxWeightKg && nextVolume > vehicle.maxVolumeM3
          ? "重量・容積"
          : nextWeight > vehicle.maxWeightKg
            ? "重量"
            : "容積";
      setValidationMsg(
        `${s.orderNo} を積むと${which}が積載上限を超えます。積み残し処理を検討してください。`,
      );
      return;
    }
    setValidationMsg(null);
    setAssignment((a) => ({ ...a, [s.id]: "割当済" }));
    setPreviewId(null);
    bumpStatusToLoading();
    setAnnounce(`${s.orderNo} を ${vehicle.name} に割り当てました。`);
  }

  function unassign(s: Shipment) {
    if (readOnly) return;
    setAssignment((a) => ({ ...a, [s.id]: "未割当" }));
    setValidationMsg(null);
    setAnnounce(`${s.orderNo} の割当を解除しました。`);
  }

  function openDefer(s: Shipment) {
    if (readOnly) return;
    setDeferTarget(s);
    setDeferReason(DEFER_REASONS[0]);
  }

  function confirmDefer() {
    if (!deferTarget) return;
    const s = deferTarget;
    setAssignment((a) => ({ ...a, [s.id]: "積み残し" }));
    setDeferred((d) => ({ ...d, [s.id]: { id: s.id, reason: deferReason } }));
    setValidationMsg(null);
    setAnnounce(`${s.orderNo} を積み残し（次便へ振替）にしました。理由: ${deferReason}`);
    setDeferTarget(null);
  }

  function undefer(s: Shipment) {
    if (readOnly) return;
    setAssignment((a) => ({ ...a, [s.id]: "未割当" }));
    setDeferred((d) => {
      const next = { ...d };
      delete next[s.id];
      return next;
    });
    setAnnounce(`${s.orderNo} の積み残しを取り消しました。`);
  }

  // staged scan: 便/車両 → カートン
  const scanStages: ScanGateStage[] = [
    {
      id: "vehicle",
      label: "① 車両 / 便コードをスキャン",
      title: "車両",
      placeholder: vehicle.name,
      onScan: (code): ScanGateResult => {
        const v = code.trim().toUpperCase();
        const ok = v === vehicle.id.toUpperCase() || v === "RUN" || v === RUN.id.toUpperCase() || v.includes("12-34") || v.includes("56-78") || v.includes("90-12");
        if (ok) {
          setScanAnnounce({ ok: true, msg: `車両 ${vehicle.name} を確認。カートンをスキャンしてください。` });
          return { ok: true, message: "車両確認", advance: "next", value: vehicle.id };
        }
        setScanAnnounce({ ok: false, msg: `車両コードが一致しません（${code}）。` });
        return { ok: false, message: "車両コード不一致", advance: "stay" };
      },
    },
    {
      id: "carton",
      label: "② カートンのバーコードをスキャン",
      title: "カートン",
      placeholder: "CTN-7783",
      onScan: (code): ScanGateResult => {
        const v = code.trim().toUpperCase();
        const target = SHIPMENTS.find((s) => s.barcode.toUpperCase() === v);
        if (!target) {
          setScanAnnounce({ ok: false, msg: `この便に該当しないカートンです（${code}）。` });
          return { ok: false, message: "対象外カートン", advance: "stay" };
        }
        if (assignment[target.id] === "積み残し") {
          setScanAnnounce({ ok: false, msg: `${target.orderNo} は積み残し処理済みです。` });
          return { ok: false, message: "積み残し済", advance: "stay" };
        }
        if (assignment[target.id] !== "割当済" && assignment[target.id] !== "積込済") {
          setScanAnnounce({
            ok: false,
            msg: `${target.orderNo} は未割当です。先に割り当ててください。`,
          });
          return { ok: false, message: "未割当", advance: "stay" };
        }
        if (assignment[target.id] === "積込済") {
          setScanAnnounce({ ok: false, msg: `${target.orderNo} は既に積込済みです。` });
          return { ok: false, message: "重複スキャン", advance: "stay" };
        }
        setAssignment((a) => ({ ...a, [target.id]: "積込済" }));
        bumpStatusToLoading();
        setScanAnnounce({
          ok: true,
          msg: `${target.orderNo}（${target.cartons}個）を積込済みにしました。`,
        });
        return { ok: true, message: "積込完了", advance: "stay", value: target.id };
      },
    },
  ];

  function moveStop(index: number, dir: -1 | 1) {
    if (readOnly) return;
    setStopOrder((order) => {
      const next = [...order];
      const target = index + dir;
      if (target < 0 || target >= next.length) return order;
      [next[index], next[target]] = [next[target], next[index]];
      return next;
    });
    const moved = orderedStops[index];
    setAnnounce(`${moved?.name ?? "停車地"} を${dir === -1 ? "上" : "下"}へ移動しました。`);
  }

  function attemptDispatch() {
    if (!canDispatch) {
      setValidationMsg(
        dispatchBlockers[0] ?? "出発条件を満たしていません。",
      );
      return;
    }
    setStatus("出発済");
    setValidationMsg(null);
    setAnnounce("出発を確定しました。ドライバーへ配送指示を送信しました。");
    setSummaryOpen(true);
  }

  function resetRun() {
    setAssignment(Object.fromEntries(SHIPMENTS.map((s) => [s.id, "未割当" as AssignState])));
