                  {/* per-shipment inline contribution preview against the load */}
                  <div className="mt-3">
                    <CapacityMeter
                      label="この出荷"
                      value={s.weightKg}
                      max={vehicle.maxWeightKg}
                      unit="kg"
                      size="inline"
                      thresholds={LOAD_THRESHOLDS}
                    />
                  </div>
                </li>
              );
            })}
          </ul>
        </CardContent>
      </Card>

      {/* ── 積込スキャン ─────────────────────────────────────────────────── */}
      <Card>
        <CardHeader className="pb-3">
