                      <li key={b}>{b}</li>
                    ))}
                  </ul>
                </AlertDescription>
              </Alert>
            ) : (
              <Alert variant="success">
                <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
                <AlertTitle as="h3">出発条件を満たしました</AlertTitle>
                <AlertDescription>積載・積込・ルートすべて確認済みです。出発を確定できます。</AlertDescription>
              </Alert>
            )}
          </div>

          <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
            <p className="text-xs text-muted-foreground tabular-nums" aria-live="polite">
              重量 {formatNumber(loadedWeight)}/{formatNumber(vehicle.maxWeightKg)}kg ·
              容積 {fmt1(loadedVolume)}/{fmt1(vehicle.maxVolumeM3)}m³ ·
              積込 {loadedShipments.length}/{assignedShipments.length} 件 · 停車 {stopsWithLoad}
            </p>
            <div className="flex flex-wrap gap-2">
              {readOnly ? (
                <>
                  <Button variant="outline" onClick={() => setSummaryOpen(true)}>
                    配車サマリ
                  </Button>
                  <Button variant="outline" onClick={() => setPrintOpen(true)}>
                    <IconPrinter className="mr-1 h-4 w-4" aria-hidden="true" />
                    配送指示書印刷
                  </Button>
                  <Button variant="secondary" onClick={resetRun}>
                    新しい配車
                  </Button>
                </>
              ) : (
                <>
                  <Button variant="outline" onClick={() => setPrintOpen(true)}>
                    <IconPrinter className="mr-1 h-4 w-4" aria-hidden="true" />
                    配送指示書印刷
                  </Button>
                  <Button variant="outline" onClick={() => setSummaryOpen(true)}>
                    配車サマリ
                  </Button>
                  <Button variant="success" onClick={attemptDispatch} disabled={!canDispatch}>
                    <IconChevronRight className="mr-1 h-4 w-4" aria-hidden="true" />
                    出発確定
                  </Button>
                </>
              )}
            </div>
          </div>
        </CardContent>
      </Card>

      {/* 積み残し処理 dialog */}
      <Dialog open={deferTarget !== null} onOpenChange={(o) => !o && setDeferTarget(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>積み残し処理</DialogTitle>
            <DialogDescription>
              {deferTarget?.orderNo}（{deferTarget?.cartons}個 / {deferTarget ? formatNumber(deferTarget.weightKg) : 0}kg）を次便へ振り替えます。
            </DialogDescription>
          </DialogHeader>
          <Select
            label="理由"
            value={deferReason}
            onChange={(e) => setDeferReason(e.target.value)}
          >
            {DEFER_REASONS.map((r) => (
              <option key={r} value={r}>
                {r}
              </option>
            ))}
          </Select>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDeferTarget(null)}>
              キャンセル
            </Button>
            <Button variant="warning" onClick={confirmDefer}>
              積み残しにする
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* 配車サマリ dialog */}
      <Dialog open={summaryOpen} onOpenChange={setSummaryOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>配車サマリ</DialogTitle>
            <DialogDescription>
              {RUN.name} ・ {vehicle.name} ・ {driver.name}
            </DialogDescription>
          </DialogHeader>
          <div className="flex flex-col gap-3 text-sm">
            <CapacityMeter
              label="重量積載率"
              value={loadedWeight}
              max={vehicle.maxWeightKg}
              unit="kg"
              size="inline"
              thresholds={LOAD_THRESHOLDS}
            />
            <CapacityMeter
              label="容積積載率"
              value={loadedVolume}
              max={vehicle.maxVolumeM3}
              unit="m³"
              size="inline"
              thresholds={LOAD_THRESHOLDS}
            />
            <Separator />
            <dl className="grid grid-cols-2 gap-2 tabular-nums">
              <dt className="text-muted-foreground">割当出荷</dt>
              <dd className="text-right font-medium">{assignedShipments.length} 件</dd>
              <dt className="text-muted-foreground">積込個数</dt>
              <dd className="text-right font-medium">{formatNumber(loadedCartons)} 個</dd>
              <dt className="text-muted-foreground">停車地</dt>
              <dd className="text-right font-medium">{stopsWithLoad} 箇所</dd>
              <dt className="text-muted-foreground">所要 / 帰着</dt>
              <dd className="text-right font-medium">約{totalMinutes}分 / {finishEta}</dd>
              <dt className="text-muted-foreground">代引回収</dt>
              <dd className="text-right font-medium">{formatCurrency(codTotal)}</dd>
              <dt className="text-muted-foreground">積み残し</dt>
              <dd className="text-right font-medium">{Object.keys(deferred).length} 件</dd>
            </dl>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setSummaryOpen(false)}>
              閉じる
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* 配送指示書 dialog */}
      <Dialog open={printOpen} onOpenChange={setPrintOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>配送指示書</DialogTitle>
            <DialogDescription>{RUN.name} / {RUN.date}</DialogDescription>
          </DialogHeader>
          <div className="flex flex-col gap-2 text-sm">
            <p>
              <span className="text-muted-foreground">車両 </span>
              {vehicle.name}（{vehicle.type}）
            </p>
            <p>
              <span className="text-muted-foreground">ドライバー </span>
              {driver.name} ・ 出発 {RUN.departAt}
            </p>
            <Separator className="my-1" />
            <ol className="list-decimal pl-5">
              {stopEtas.map(({ stop, eta, cartons }) => (
                <li key={stop.id} className="tabular-nums">
                  {stop.name} — 到着 {eta} ・ {cartons}個
                </li>
              ))}
            </ol>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setPrintOpen(false)}>
              閉じる
            </Button>
            <Button variant="primary" onClick={() => window.print()}>
              <IconPrinter className="mr-1 h-4 w-4" aria-hidden="true" />
              印刷
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </main>
  );
}
